INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1373, 141270, 6, 248, '快乐', '从聊天中,得知这几天,他过得不太开心.不喜欢见他眉头紧锁的样子,有点像个小老头.如果可以的话,我愿意把我的快乐和他一起分享.要是在以前,我一定是拉着他到海边,听听海浪声,看看远远的地方海天成一色,这样,看完海后,他的心情就会像天空一样的晴朗.可是现在,我们只是朋友了,不知道他是否还会去海边散心吗?或许有另一个女生用另一种方式让他快乐了!不管他现在牵着谁的手,我都会在心里默默为他祝福,祝他快乐!', '从聊天中,得知这几天,他过得不太开心.不喜欢见他眉头紧锁的样子,有点像个小老头.如果可以的话,我愿意把我的快乐和他一起分享.要是在以前,我一定是拉着他到海边,听听海浪声,看看远远的地方海天成一色,这样,看完海后,他的心情就会像天空一样的晴朗.可是现在,我们只是朋友了,不知道他是否还会去海边散心吗?或许有另一个女生用另一种方式让他快乐了!不管他现在牵着谁的手,我都会在心里默默为他祝福,祝他快乐!', '世界上最远的距离不是天涯海角,不是生离死别,而是我站在你面前,你却不知道我爱你!~~~~~', '2002-01-15 15:31:00', 1, '20030122190340_bbsid_141270_board_6_5942717d31.html', '20030122190340');
